function reverse(x: number): number {
  const INT_MAX = 2147483647, INT_MIN = -2147483648;
  const sign = x < 0 ? -1 : 1;
  let n = Math.abs(x), r = 0;
  while (n > 0) { r = r * 10 + n % 10; n = Math.floor(n / 10); }
  r *= sign;
  if (r > INT_MAX || r < INT_MIN) return 0;
  return r;
}
